// src/services/email.js
// Confirmación al distribuidor + notificación interna GPA.
// Imagen: Ecosistema Inter Water Smart (CID embebido).

const { SESClient, SendRawEmailCommand } = require('@aws-sdk/client-ses');
const nodemailer = require('nodemailer');
const logger     = require('../utils/logger');

// Amazon SES — correo remitente verificado: procesos@gpa.com.mx
// TI debe verificar este correo en:
//   AWS Console → Amazon SES → Verified Identities → Create Identity → Email address
//   Ingresar: procesos@gpa.com.mx → AWS manda link de confirmación → hacer clic → listo.
// También dar permiso IAM a las Lambdas: Action: "ses:SendRawEmail"

const ses = new SESClient({ region: process.env.AWS_REGION || 'us-east-1' });

const transporter = nodemailer.createTransport({
  SES: { ses, aws: { SendRawEmailCommand } },
});

const FROM = 'GPA Postventa <procesos@gpa.com.mx>';

const CORREOS_FIJOS = [
  'atencion.clientes@gpa.com.mx',
  'devoluciones@gpa.com.mx',
  'procesos@gpa.com.mx',
  'postventa@gpa.com.mx',
];

const TIPO_LABEL = { gar: 'Garantía', dev: 'Devolución', at: 'Apoyo Técnico' };

// Imagen Ecosistema Inter Water Smart — 600x400px, JPEG, ~59KB
const BANNER_B64 = '';

const BANNER = {
  filename: 'ecosistema-inter-water-smart.jpg',
  content:  Buffer.from(BANNER_B64, 'base64'),
  cid:      'banner_gpa',
  contentType: 'image/jpeg',
};


function fila(label, value) {
  return `<tr>
    <td style="padding:8px 14px;border-bottom:1px solid #DDE4EE;color:#64748B;white-space:nowrap;font-size:13px;">${label}</td>
    <td style="padding:8px 14px;border-bottom:1px solid #DDE4EE;font-size:13px;">${value}</td>
  </tr>`;
}

// ── Confirmación al distribuidor ──────────────────────────────────────────────
// to: email1 (obligatorio) + email2 + email3 (opcionales si fueron capturados)
async function sendConfirmacion(ticket) {
  const tipo  = TIPO_LABEL[ticket.tipo_ticket] || ticket.tipo_ticket;
  const folio = ticket.folio_sap || 'Pendiente de asignación';
  const toList = [ticket.email_contacto, ticket.email2, ticket.email3]
    .filter(Boolean).filter(e => e.includes('@'));

  await transporter.sendMail({
    from:        FROM,
    to:          toList.join(', '),
    subject:     `GPA Postventa — Solicitud recibida · ${folio}`,
    attachments: [BANNER],
    html: `<div style="font-family:Arial,sans-serif;max-width:620px;margin:0 auto;">
      <div style="background:#003D7A;padding:24px 32px;">
        <h2 style="color:white;margin:0;font-size:20px;">General de Productos para el Agua</h2>
        <p style="color:#90CAF9;margin:4px 0 0;font-size:13px;">Portal de Postventa — Confirmación de solicitud</p>
      </div>
      <div style="padding:28px 32px;border:1px solid #DDE4EE;border-top:none;">
        <p style="font-size:15px;">Hola <strong>${ticket.nombre_contacto}</strong>,</p>
        <p style="font-size:14px;color:#475569;line-height:1.6;">
          Tu solicitud de <strong>${tipo}</strong> fue recibida por el equipo de Postventa.
          Nos pondremos en contacto contigo <strong>a más tardar en 1 día hábil</strong>
          para validar la información e informarte los pasos procedentes a seguir.
        </p>
        <table style="width:100%;border-collapse:collapse;margin:20px 0;">
          <tr style="background:#E8F2FF;">
            <td colspan="2" style="padding:10px 14px;font-weight:700;color:#003D7A;font-size:13px;">Resumen de tu solicitud</td>
          </tr>
          ${fila('Folio', `<strong style="color:#003D7A;font-size:16px;">${folio}</strong>`)}
          ${fila('Tipo', tipo)}
          ${fila('Familia', ticket.familia)}
          ${fila('No. de Factura', ticket.numero_factura)}
          ${fila('Producto', ticket.codigo_producto)}
          ${fila('Estado', '<span style="color:#D97706;font-weight:600;">En revisión por Postventa</span>')}
        </table>
        <div style="background:#E8F2FF;border-radius:8px;padding:12px 16px;margin:16px 0;">
          <p style="margin:0;font-size:14px;color:#003D7A;">
            📞 <strong>800 APOYO GPA</strong> (800 276 9647)<br>
            📧 <a href="mailto:postventa@gpa.com.mx" style="color:#0060B8;">postventa@gpa.com.mx</a>
          </p>
        </div>
        <div style="margin:24px 0 8px;">
          <img src="cid:banner_gpa" alt="Ecosistema Inter Water Smart — GPA"
               style="width:100%;max-width:556px;border-radius:8px;display:block;"/>
        </div>
        <p style="font-size:11px;color:#94A3B8;text-align:center;margin:4px 0 0;">
          Conoce el Ecosistema Inter Water Smart — tecnología de punta para tu alberca
        </p>
      </div>
      <div style="background:#F4F7FB;padding:16px 32px;text-align:center;border:1px solid #DDE4EE;border-top:none;">
        <p style="margin:0;font-size:11px;color:#94A3B8;">
          General de Productos para el Agua S.A. de C.V. &nbsp;·&nbsp;
          <a href="mailto:postventa@gpa.com.mx" style="color:#0060B8;">postventa@gpa.com.mx</a>
        </p>
      </div>
    </div>`,
  }).catch(err => logger.error('Error confirmación', { error: err.message }));
}

// ── Notificación interna ───────────────────────────────────────────────────────
// to: 4 correos fijos + ejecutivo GPA + gerente de sucursal (vienen de SAP)
async function sendNotificacionInterna(ticket, evidencias) {
  const tipo  = TIPO_LABEL[ticket.tipo_ticket] || ticket.tipo_ticket;
  const folio = ticket.folio_sap || ticket.id;

  const toList = [
    ...CORREOS_FIJOS,
    ticket.ejecutivo_gpa_email,  // se obtiene de SAP BusinessPartners
    ticket.gerente_email,         // se obtiene de SAP BusinessPartners
  ].filter(Boolean).filter(e => e.includes('@'));

  const evHtml = evidencias.map(ev => {
    const n = (ev.archivos_s3 || []).length;
    const estado = n > 0
      ? `<span style="color:#16A34A;">✓ ${n} archivo(s)</span>`
      : ev.justificacion
        ? `<span style="color:#D97706;">⚠ ${ev.justificacion}</span>`
        : `<span style="color:#DC2626;">✗ Sin adjuntar</span>`;
    return `<tr>
      <td style="padding:6px 12px;border-bottom:1px solid #DDE4EE;font-size:12px;">${ev.nombre}</td>
      <td style="padding:6px 12px;border-bottom:1px solid #DDE4EE;font-size:12px;text-align:center;font-weight:700;color:${ev.tipo_requerimiento==='O'?'#003D7A':'#D97706'};">${ev.tipo_requerimiento}</td>
      <td style="padding:6px 12px;border-bottom:1px solid #DDE4EE;font-size:12px;">${estado}</td>
    </tr>`;
  }).join('');

  await transporter.sendMail({
    from:    FROM,
    to:      toList.join(', '),
    subject: `[NUEVO TICKET] ${tipo} · ${ticket.nombre_empresa} · ${ticket.familia} · ${folio}`,
    html: `<div style="font-family:Arial,sans-serif;max-width:680px;margin:0 auto;">
      <div style="background:#003D7A;padding:20px 28px;">
        <h2 style="color:white;margin:0;font-size:18px;">Nuevo ticket de Postventa</h2>
        <p style="color:#90CAF9;margin:4px 0 0;font-size:12px;">Notificación automática — Portal GPA Postventa</p>
      </div>
      <div style="padding:24px 28px;border:1px solid #DDE4EE;border-top:none;">
        <table style="width:100%;border-collapse:collapse;font-size:13px;margin-bottom:20px;">
          <tr style="background:#E8F2FF;">
            <td colspan="2" style="padding:10px 14px;font-weight:700;color:#003D7A;">Datos del ticket</td>
          </tr>
          ${fila('Folio SAP', `<strong style="color:#003D7A;font-size:15px;">${folio}</strong>`)}
          ${fila('Tipo', tipo)}
          ${fila('Distribuidor', ticket.nombre_empresa)}
          ${fila('Ejecutivo GPA', ticket.ejecutivo_gpa)}
          ${fila('Categoría', ticket.categoria)}
          ${fila('Familia', ticket.familia)}
          ${fila('No. Factura', ticket.numero_factura)}
          ${fila('Producto', ticket.codigo_producto)}
          ${ticket.numero_serie ? fila('N° Serie/Lote', ticket.numero_serie) : ''}
          ${fila('Contacto', `${ticket.nombre_contacto} · ${ticket.telefono}`)}
          ${fila('Correo(s)', [ticket.email_contacto, ticket.email2, ticket.email3].filter(Boolean).join(' · '))}
          ${fila('Descripción', ticket.descripcion)}
        </table>
        <h3 style="color:#003D7A;border-bottom:2px solid #003D7A;padding-bottom:8px;font-size:14px;">Evidencias</h3>
        <table style="width:100%;border-collapse:collapse;">
          <thead><tr style="background:#E8F2FF;">
            <th style="padding:8px 12px;text-align:left;font-size:12px;">Evidencia</th>
            <th style="padding:8px 12px;text-align:center;font-size:12px;">Req.</th>
            <th style="padding:8px 12px;text-align:left;font-size:12px;">Estado</th>
          </tr></thead>
          <tbody>${evHtml}</tbody>
        </table>
      </div>
      <div style="background:#F4F7FB;padding:12px 28px;text-align:center;border:1px solid #DDE4EE;border-top:none;">
        <p style="margin:0;font-size:11px;color:#94A3B8;">General de Productos para el Agua — Notificación interna</p>
      </div>
    </div>`,
  }).catch(err => logger.error('Error notificación interna', { error: err.message }));
}

module.exports = { sendConfirmacion, sendNotificacionInterna };
